#include "AS726X.h"
#include&lt;Wire.h&gt;
#define AS7263_I2C_ADDRESS 0x49
#define TCA_I2C_ADDRESS    0x70
#include &lt;SoftwareSerial.h&gt;
#define NUMBER_OF_SENSORS 2
#define DONEPIN 9
#include &lt;SPI.h&gt;
#include "SdFat.h"
#include "RTClib.h"
SdFat sd;
SdFile myFile;

const int chipSelect = 10;

int cycles = 0;
float up_ir;
float up_vis;
float down_ir;
float down_vis;
int i =0;
float NDVI;
float NIRup;
float VISup;
